        const startBearing = map.getBearing();
        const targetBearing = info.flipBearing;
        const bearingDelta = targetBearing - startBearing;
        const easeInOut = t => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;
        let flipLng = map.getCenter().lng;
